#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI N=1e7+5,MOD=1e9;
int seed,n,k,d,x,tp,f[N],a[N],q[N],l=1,r=0;
int rnd()
{
	return seed=(1LL*seed*0x66CCFF%MOD+20120712)%MOD;
}
signed main()
{
	IOS
	cin>>n>>k>>d>>x>>tp;
	if(tp)
	{
		cin>>seed;
	}
	FOR(i,1,n)
	{
		if(tp==0)
		{
			cin>>a[i];
		}
		else
		{
			a[i]=rnd();
		}
	}
	FOR(i,2,n)
	{
		f[i]=N;
	}
	f[1]=a[1];
	FOR(i,2,n)
	{
		wh(l<=r&&f[q[r]]-q[r]*d>=f[i-1]-(i-1)*d)
		{
			r--;
		}
		q[++r]=i-1;
		wh(l<=r&&q[l]<i-x)
		{
			l++;
		}
		f[i]=f[q[l]]-q[l]*d+(i-1)*d+a[i]+k;
	}
	cout<<f[n];
	return 0;
}
